        },
        server: {
            auto_reconnect: true,
            poolSize: 5
        }
    },
    callbacksCalled = {};

function runTest(db, col) {
    var i = 0;

    function next(cursor, id) {
        cursor.nextObject(function (err, doc) {
            if (err) {
                console.log('nextObject', id, 'error:', err);
            } else {
